$--pagination-button-width--mobile: 36px;
$--pagination-button-width--desktop: 44px;

.swiper-wrapper {
  figure {
    margin: 0;
    padding: 0;
    cursor: pointer;
    transition: transform 0.3s;

    &:hover,
    &:focus {
      transform: scale(1.05) rotate(0deg);
    }
  }
  .swiper-button-prev,
  .swiper-button-next {
    top: 0;
    bottom: 0;
    width: 88px;
    margin-top: 0;
    height: 100%;

    &:after {
      opacity: 0.4;
      background: #fff;
      width: $--pagination-button-width--desktop;
      height: $--pagination-button-width--desktop;
      text-align: center;
      font-size: 22px;
      line-height: $--pagination-button-width--desktop;
      border-radius: 50%;
      transition: opacity 0.3s;

      @media (max-width: 983px) {
        width: $--pagination-button-width--mobile;
        height: $--pagination-button-width--mobile;
        line-height: $--pagination-button-width--mobile;
        position: relative;
      }
    }

    &--small {
      &:after {
        font-size: 16px;
        width: 40px;
        height: 40px;
        line-height: 40px;
      }
    }

    &:active {
      &:after {
        opacity: 1;
      }
    }

    @media (min-width: 984px) {
      &:hover,
      &:focus {
        &:after {
          opacity: 1;
        }
      }
    }
  }
  .swiper-button-prev {
    left: 0;
    &:after {
      left: -10px;
    }
  }
  .swipe

