.quokkarize-image {
  position: fixed !important;
  -webkit-overflow-scrolling: touch;
  top: 0;
  bottom: 0;
  left: 0;
  right: 0;
  margin: auto;
  width: 40%;
  z-index: 100;
}
.slide-leave-active,
.slide-enter-active {
  -webkit-transform: translateZ(0);
  backface-visibility: hidden;
  perspective: 1000;
  transition: 0.3s;
  opacity: 1;
  transform: scaleY(1);
  transform-origin: center top;
}
.slide-enter,
.slide-leave-to {
  -webkit-transform: translateZ(0);
  backface-visibility: hidden;
  perspective: 1000;
  transform: translate(0, 100%);
}
.slide-up-leave-to {
  -webkit-transform: translateZ(0);
  backface-visibility: hidden;
  perspective: 1000;
  transform: translate(0, -100%);
}

.slide-up-leave-to {
  -webkit-transform: translateZ(0);
  backface-visibility: hidden;
  perspective: 1000;
  transform: translate(0, -100%);
}
