.dropdown-label {
  height: 44px;
  padding: 0 14px 0 8px;
  border-radius: 6px;
  border: solid 1px hsl(216, 21%, 82%);
  flex-grow: 1;
  color: #56595e;
  background: #fff;
  border: 1px solid #92959b;
  box-sizing: border-box;
  font-size: 1em;
  text-align: left;
  width: 100%;

  &:focus {
    outline-width: 1px !important;
    outline-style: solid;
    outline-color: #383b3e;
    @media (-webkit-min-device-pixel-ratio: 0) {
      outline: auto 4px !important;
      outline-offset: -1px;
    }
  }

  ::v-deep(.el-icon--right) {
    float: right;
    top: 8px;
    position: relative;
  }
}
.dropdown-body {
  margin-top: 36px;
  background: white;
  position: absolute;
  top: 20px;
  z-index: 2020;
  border: 1px solid;
  box-sizing: border-box;
  padding: 16px;
  width: auto;
  min-width: 100%;

  &:before,
  &:after {
    content: ' ';
    width: 0;
    height: 0;
    position: absolute;
    pointer-events: none;
    border-style: solid;
    border-width: 0 8px 12px 8px;
    border-color: transparent transparent #fff transparent;
  }

  &:before {
    border-bottom-color: #fff;
    top: -11px;
    right: 50%;
    z-index: 2021;
  }

  &:after {
    border-bottom-color: #c6ceda;
    top: -13px;
    right: 50%;
    z-index: 1;
  }
}
.custom-html-dropdown {
  position: relative;
  font-size: 1rem;
  label {
    font-size: 0.875em;
    position: absolute;
    background: #fff;
    top: -11px;
    left: 6px;
    color: #56595e;
    padding: 0 4px;
  }
}
